package com.example.oauth2.client;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.util.UriComponentsBuilder;

import java.net.URI;

@Controller
@RequestMapping("/oauth2")
public class OAuth2ClientController {

    @Value("${oauth2.client.id}")
    private String clientId;

    @Value("${oauth2.client.redirect-uri}")
    private String redirectUri;

    @Value("${oauth2.client.authorization-uri}")
    private String authorizationUri;

    @Value("${oauth2.client.scope}")
    private String scope;

    @GetMapping("/login")
    public String redirectToAuthorizationServer() {
        String authorizationUrl = UriComponentsBuilder.fromHttpUrl(authorizationUri)
                .queryParam("client_id", clientId)
                .queryParam("redirect_uri", redirectUri)
                .queryParam("scope", scope)
                .queryParam("response_type", "code")
                .toUriString();
        
        return "redirect:" + authorizationUrl;
    }
}